#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;
#define int ll
int ans,dp[1010][10][10][2][2],a[1010],n;
inline void DN(int &x){} inline void UP(int &x){}
inline int rd(int *a)
{
	int p=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')a[++p]=ch^48,ch=getchar();reverse(a+1,a+p+1);return p;
}
inline int S()
{
	if(n==1)return 0;memset(dp,0,sizeof(dp));
	rep(0,9,i)rep(0,9,j)
	{
		dp[2][i][j][i==j][0]=1;
		if(i<a[2]||(i==a[2]&&j<=a[1]))dp[2][i][j][i==j][1]=1;
	}
	rep(2,n-1,d)
	{
		rep(0,9,i)
		{
			rep(0,9,j)
			{
				rep(0,1,p)
				{
					int *w=dp[d][i][j][p];
					rep(0,9,k)
					{
						bool np=p|(k==i||k==j);
						DN(dp[d+1][k][i][np][0]+=w[0]);
						if(j<a[d-1])DN(dp[d+1][k][i][np][1]+=w[0]);
						else if(j==a[d-1])DN(dp[d+1][k][i][np][1]+=w[1]);
					}
				}
			}
		}
	}
	int ans=0;
	rep(1,n-1,d){rep(1,9,i)rep(0,9,j)DN(ans+=dp[d][i][j][1][0]);}
	rep(1,a[n]-1,i)rep(0,9,j)DN(ans+=dp[n][i][j][1][0]);
	rep(0,a[n-1]-1,j)DN(ans+=dp[n][a[n]][j][1][0]);
	DN(ans+=dp[n][a[n]][a[n-1]][1][1]);
	return ans;
}
signed main()
{
	n=rd(a);UP(ans=-S());bool flag=0;
	rep(2,n,i)if(a[i]==a[i-1]){flag=true;break;}
	if(!flag)rep(3,n,i)if(a[i]==a[i-2]){flag=true;break;}
	if(flag)DN(++ans);
	ll res=0;drep(n,1,i)res=res*10+a[i];ll dlt=-res+1;
	n=rd(a);DN(ans+=S());res=0;drep(n,1,i)res=res*10+a[i];dlt+=res;
	printf("%lld\n",dlt-ans);
}
